#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

void merge(vector<int>& nums, int left, int right)
{
    int i = left, j = right, k = left + right - 1;
    while (i < left + left && j < right)
    {
        if (nums[i] > nums[j])
            nums[k--] = nums[i--];
        else
            nums[k--] = nums[j--];
    }

    while (i < left + left)
    {
        nums[k--] = nums[i--];
    }

    while (j < right)
    {
        nums[k--] = nums[j--];
    }
}

vector<int> sortArray(vector<int>& nums)
{
    if (nums.size() < 2)
        return nums;

    int mid = nums.size() / 2;

    vector<int> left(nums.begin(), nums.begin() + mid), right(nums.begin() + mid, nums.end());

    merge(left, left.begin(), right, right.begin(), nums.begin() + mid);

    return nums;
}

int main()
{
    vector<int> nums = {4, 2, 6, 1, 5, 3};
    sortArray(nums);
    for (int i = 0; i < nums.size(); i++)
        cout << nums[i] << ' '; 
    cout << endl;

    return 0;
}
